                  '<i class="fa fa-check-circle mr-2"></i> AI matching process completed successfully! Your job matches have been updated.' +
                  '</div>').insertAfter('.btn-primary').hide().fadeIn();

                // Reload the page after a brief delay
                setTimeout(function() {
