import React, { useState, useEffect } from 'react';
import { Container, Row, Col, Card, Alert, Button } from 'react-bootstrap';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';

function JobSeekerDashboard() {
  const { currentUser } = useAuth();
  const [profile, setProfile] = useState(null);
  const [applications, setApplications] = useState([]);
  const [matches, setMatches] = useState([]);
  const [recentJobs, setRecentJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        // Fetch user profile
        const profileRes = await axios.get('/api/profiles/me');
        setProfile(profileRes.data);

        // Fetch user applications
        const applicationsRes = await axios.get('/api/applications/me');
        setApplications(applicationsRes.data);

        // Fetch AI matches
        const matchesRes = await axios.get('/api/ai/matches');
        setMatches(matchesRes.data);

        // Fetch recent jobs
        const jobsRes = await axios.get('/api/jobs?limit=5');
        setRecentJobs(jobsRes.data);

      } catch (err) {
        console.error('Error fetching dashboard data:', err);
        setError('Failed to load dashboard data');
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, []);

  const calculateProfileCompletion = () => {
    if (!profile) return 0;

    let score = 0;
    if (profile.education) score += 25;
    if (profile.skills) score += 25;
    if (profile.interests) score += 25;
    if (profile.experience) score += 25;

    return score;
  };

  const profileCompletion = calculateProfileCompletion();

  if (loading) {
    return (
      <Container className="py-5 text-center">
        <div className="spinner-border text-primary" role="status">
          <span className="visually-hidden">Loading...</span>
        </div>
      </Container>
    );
  }

  return (
    <Container className="py-4">
      <h1 className="mb-4">Welcome, {currentUser.name}!</h1>

      {error && <Alert variant="danger">{error}</Alert>}

      {/* Profile Completion Card */}
      <Card className="shadow-sm mb-4">
        <Card.Body>
          <Row>
            <Col md={8}>
              <h5>Profile Completion</h5>
              <div className="progress mb-3">
                <div 
                  className={`progress-bar ${profileCompletion < 50 ? 'bg-warning' : 'bg-success'}`} 
                  role="progressbar" 
                  style={{ width: `${profileCompletion}%` }} 
                  aria-valuenow={profileCompletion} 
                  aria-valuemin="0" 
                  aria-valuemax="100"
                >
                  {profileCompletion}%
                </div>
              </div>
              {profileCompletion < 100 && (
                <Alert variant="info" className="mb-0">
                  <i className="bi bi-info-circle me-2"></i>
                  Complete your profile to increase your chances of finding the perfect job.
                </Alert>
              )}
            </Col>
            <Col md={4} className="text-end">
              <Link to="/profile" className="btn btn-primary">
                {profile ? 'Update Profile' : 'Create Profile'}
              </Link>
            </Col>
          </Row>
        </Card.Body>
      </Card>

      {/* Statistics Row */}
      <Row className="mb-4">
        <Col md={4}>
          <Card className="shadow-sm h-100">
            <Card.Body className="text-center">
              <h1 className="display-4">{applications.length}</h1>
              <p className="text-muted">Job Applications</p>
              <Link to="/my-applications" className="btn btn-sm btn-outline-primary">
                View Applications
              </Link>
            </Card.Body>
          </Card>
        </Col>
        <Col md={4}>
          <Card className="shadow-sm h-100">
            <Card.Body className="text-center">
              <h1 className="display-4">{matches.length}</h1>
              <p className="text-muted">AI Job Matches</p>
              <Link to="/ai-matches" className="btn btn-sm btn-outline-primary">
                View Matches
              </Link>
            </Card.Body>
          </Card>
        </Col>
        <Col md={4}>
          <Card className="shadow-sm h-100">
            <Card.Body className="text-center">
              <h1 className="display-4">{recentJobs.length}</h1>
              <p className="text-muted">New Job Listings</p>
              <Link to="/jobs" className="btn btn-sm btn-outline-primary">
                Browse Jobs
              </Link>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      {/* Recent Jobs */}
      <Card className="shadow-sm mb-4">
        <Card.Header>
          <h5 className="mb-0">Recent Job Opportunities</h5>
        </Card.Header>
        <Card.Body>
          {recentJobs.length > 0 ? (
            <div>
              {recentJobs.map(job => (
                <div key={job._id} className="border-bottom py-3">
                  <Row>
                    <Col md={8}>
                      <h5>{job.title}</h5>
                      <p className="text-muted mb-1">{job.company_name} • {job.location}</p>
                      <div><small className="text-muted">Posted on {new Date(job.created_at).toLocaleDateString()}</small></div>
                    </Col>
                    <Col md={4} className="text-end">
                      <Link to={`/jobs/${job._id}`} className="btn btn-sm btn-outline-primary">View Details</Link>
                    </Col>
                  </Row>
                </div>
              ))}
              <div className="text-center mt-3">
                <Link to="/jobs" className="btn btn-primary">
                  View All Job Listings
                </Link>
              </div>
            </div>
          ) : (
            <p className="text-center">No recent job listings available.</p>
          )}
        </Card.Body>
      </Card>

      {/* Call to Action */}
      <Card className="bg-light shadow-sm">
        <Card.Body className="p-4 text-center">
          <h4>Let AI Find Your Perfect Job Match</h4>
          <p className="mb-4">Our AI system analyzes your profile and skills to find the most suitable jobs for you.</p>
          <Button 
            variant="primary"
            as={Link}
            to="/ai-matches"
          >
            View Your AI Matches
          </Button>
        </Card.Body>
      </Card>
    </Container>
  );
}

export default JobSeekerDashboard;
</content>
